mapper.select:
select action_id, request_id, actor_user_id, target_account_id, action_type, amount, remark, create_time
from wallet_admin_action
where request_id = #{requestId}

select action_id, request_id, actor_user_id, target_account_id, action_type, amount, remark, create_time
from wallet_admin_action
where target_account_id = #{targetAccountId, jdbcType=BINARY}
order by action_id desc
limit #{limit}
